INSERT INTO `choices` VALUES (37,'Đây là một ngôn ngữ đa nền tảng, được sử dụng rộng rãi trong nhiều lĩnh vực như phát triển ứng dụng web, di động, doanh nghiệp, và hệ thống nhúng.',_binary '\0',9),(38,'Là một ngôn ngữ lập trình bậc cao, hướng đối tượng, bảo mật và mạnh mẽ, được phát triển bởi Sun Microsystems vào năm 1995. Với phương châm \"Write Once, Run Anywhere\", Java cho phép các chương trình được viết một lần và chạy trên nhiều nền tảng khác nhau nhờ vào máy ảo Java (JVM). Đây là một ngôn ngữ đa nền tảng, được sử dụng rộng rãi trong nhiều lĩnh vực như phát triển ứng dụng web, di động, doanh nghiệp, và hệ thống nhúng.',_binary '',9),(39,'Hướng đối tượng: Mọi thứ trong Java đều là đối tượng, giúp dễ dàng mở rộng và bảo trì.',_binary '\0',9),(40,'Phân tán: Được thiết kế cho các môi trường mạng và ứng dụng phân tán.',_binary '\0',9),(41,'OOP (Lập trình hướng đối tượng) là một phương pháp lập trình dựa trên khái niệm về đối tượng và lớp. OOP cho phép lập trình viên tạo ra các đối tượng trong mã, giúp quản lý, tái sử dụng và bảo trì mã dễ dàng hơn. Các đối tượng trong OOP thường chứa hai thành phần chính: dữ liệu và mã. OOP được ứng dụng rộng rãi trong nhiều ngôn ngữ lập trình như Java, PHP, Python, và Ruby',_binary '',6),(42,'OOP là Lập trình hướng đối tượng',_binary '\0',6),(43,'OOP giúp quản lý, tái sử dụng và bảo trì mã dễ dàng',_binary '\0',6),(44,'OOP cho phép lập trình viên tạo ra các đối tượng trong mã',_binary '\0',6),(45,'String, hay còn gọi là chuỗi ký tự, là một dãy các ký tự được xếp nối tiếp nhau theo một thứ tự nhất định. Mỗi ký tự có thể là chữ cái, chữ số, ký hiệu đặc biệt hoặc khoảng trắng',_binary '\0',10),(46,'Hiển thị thông tin và giao tiếp với người dùng (thông báo, câu lệnh hiển thị, nhập dữ liệu từ bàn phím)',_binary '\0',10),(47,'Trong lập trình, string là kiểu dữ liệu biểu diễn một chuỗi ký tự, dùng để lưu trữ và xử lý văn bản.',_binary '',10),(48,'Lập trình web và API (HTML, CSS, JavaScript, URL, request/response JSON)',_binary '\0',10),(49,'ArithmeticException: Xảy ra khi có lỗi trong các phép toán số học, chẳng hạn như chia cho 0.',_binary '\0',11),(50,'NullPointerException: Xảy ra khi cố gắng truy cập một đối tượng mà chưa được khởi tạo.',_binary '\0',11),(51,'IOException: Xảy ra khi có lỗi trong quá trình nhập/xuất dữ liệu, chẳng hạn như không thể đọc hoặc ghi vào một tệp tin.',_binary '\0',11),(52,'Exception là một thuật ngữ trong lập trình và công nghệ thông tin, dùng để chỉ một tình huống hoặc điều kiện đặc biệt xảy ra trong quá trình thực thi chương trình, khiến chương trình không thể tiếp tục hoạt động bình thường. Khi một exception xảy ra, chương trình sẽ dừng lại và chuyển quyền kiểm soát đến một đoạn mã đặc biệt gọi là \"exception handler\" để xử lý tình huống này.',_binary '',11),(53,'Là một cơ chế cho phép chương trình kiểm tra và thao tác với cấu trúc của lớp, đối tượng, phương thức, và thuộc tính tại thời gian chạy (runtime), ngay cả khi bạn không biết trước tên lớp hoặc thành phần đó khi biên dịch.',_binary '',12),(54,'Lấy thông tin về class (tên, package, modifiers, superclass, interfaces).',_binary '\0',12),(55,'Lấy danh sách fields, methods, constructors.',_binary '\0',12),(56,'Gọi phương thức hoặc truy cập thuộc tính (kể cả private) khi đang chạy chương trình.',_binary '\0',12),(57,'Stream API: Introduced to process collections and arrays in a functional style. It supports operations like filtering, mapping, and reducing, executed lazily for better performance.',_binary '\0',13),(58,'Java 8, released on March 18, 2014, is a revolutionary version of the Java programming language and platform. It introduced significant enhancements to the language, JVM, tools, and libraries, making it a milestone in Java\'s evolution.',_binary '',13),(59,'Default Methods: Interfaces can now have methods with default implementations, enabling backward compatibility and reducing boilerplate code.',_binary '\0',13),(60,'Optional Class: Helps avoid NullPointerException by providing a container object that may or may not contain a non-null value.',_binary '\0',13),(61,'Sealed Classes (lớp niêm phong): Giúp kiểm soát những lớp nào có thể kế thừa một lớp cha, tăng độ an toàn và rõ ràng trong thiết kế hệ thống.',_binary '\0',14),(62,'Pattern Matching cho instanceof: Giúp rút gọn cú pháp khi kiểm tra kiểu dữ liệu và ép kiểu.',_binary '\0',14),(63,'Java 17 là phiên bản mới nhất của ngôn ngữ lập trình Java, được phát hành vào ngày 15 tháng 9 năm 2021. Đây là phiên bản Long-Term Support (LTS) cho Java SE, cho phép người dùng sử dụng các tệp biên dịch JDK 17 miễn phí trong sản xuất và tái phân phối. Java 17 bao gồm nhiều tính năng mới, trong đó có gần gũi hơn với các tệp số nguyên ngẫu nhiên và các tệp mã điều khiển cho các hàm ngoại giao và API bộ nhớ. Phiên bản này cũng có các tính năng bảo mật như các tệp mã điều khiển có ngữ cảnh cho việc khai thác dữ liệu',_binary '',14),(64,'Records (bản ghi): Giúp định nghĩa các lớp dữ liệu bất biến một cách ngắn gọn hơn.',_binary '\0',14);
/*!40000 ALTER TABLE `choices` ENABLE KEYS */;
