INSERT INTO `lessons` VALUES (3,'Nhắc lại một chút về Java cơ bản, các nguyên lý OOP và 1 số đặc điểm đặc trưng của Java','2026-02-25 09:55:00.239977',1,'Java cơ bản và OOP','https://res.cloudinary.com/drozgbjpm/video/upload/v1773131393/eduflow/videos/e6034670-9227-4b5f-8f82-50e73dc1d208.mp4',1),(4,'Giới thiệu về cấu trúc dữ liệu Collection, bao gồm Array, List, Set, Queue, Map, Vector','2026-02-25 09:56:05.344783',2,'Collection','',1),(5,'Các thao tác cơ bản dựa trên String và các class phụ trợ, xử lý dữ liệu DateTime trong java, xử lý đa luồng cơ bản trong java bằng Thread và Runnable','2026-02-25 09:56:49.761377',3,'String, DateTime và Thread','',1),(6,'Ngoại lệ và xử lý ngoại lệ trong Java','2026-02-25 09:57:29.961523',4,'Exception','',1),(7,'Giới thiệu qua về Reflection API của Java','2026-02-25 09:57:47.844539',5,'Reflection','',1),(8,'Giới thiệu về Java 8 và các tính năng nổi trội: Stream, Optional, Functional interfaces, lambda, ...','2026-02-25 09:58:24.618146',6,'Java 8','',1),(9,'Giới thiệu về các tính năng mới từ Java 9 -> 17','2026-02-25 09:58:48.657693',7,'Java 17','',1),(10,'Sơ qua về cấu trúc dự án MVC','2026-02-25 09:59:23.073304',1,'MVC','',2),(11,'Giới thiệu về một số module phổ biến trong Spring','2026-02-25 09:59:38.924494',2,'Spring Boot','',2),(12,'Sơ qua về JPA và JDBC, sử dụng trong Spring JPA như thế nào','2026-02-25 09:59:53.782940',3,'JPA','',2),(13,'Giới thiệu về Spring Security, cách authen dựa trên JWT','2026-02-25 10:00:08.160374',4,'Spring Security và JWT','',2),(14,'Tổng quan về Vue.js: Lịch sử, ưu điểm, và so sánh với các framework khác.','2026-02-25 10:01:50.756994',5,'Giới thiệu VueJS','',2),(15,'Mục Tiêu: Trong video này tôi giúp anh em hiểu và làm việc được với MySQL (giúp anh em tiết kiệm nhiều giờ đọc tài liệu)','2026-03-04 13:33:39.701211',1,'Làm quen với mySQL','https://www.youtube.com/watch?v=TslBGnENTFw',3);
/*!40000 ALTER TABLE `lessons` ENABLE KEYS */;
UNLOCK TABLES;

