INSERT INTO `question_replies` VALUES (1,1,1,'Collection trong Java là một interface đại diện cho nhóm các đối tượng, giúp lập trình viên thao tác dễ dàng với dữ liệu như thêm, xóa, tìm kiếm và sắp xếp.',1,'2026-03-16 14:32:30');
