--

LOCK TABLES `questions` WRITE;
/*!40000 ALTER TABLE `questions` DISABLE KEYS */;
INSERT INTO `questions` VALUES (6,'OOP là gì ?','OOP (Lập trình hướng đối tượng) là một phương pháp lập trình dựa trên khái niệm về đối tượng và lớp. OOP cho phép lập trình viên tạo ra các đối tượng trong mã, giúp quản lý, tái sử dụng và bảo trì mã dễ dàng hơn. Các đối tượng trong OOP thường chứa hai thành phần chính: dữ liệu và mã. OOP được ứng dụng rộng rãi trong nhiều ngôn ngữ lập trình như Java, PHP, Python, và Ruby',1,1,12),(9,'Java là gì','Java là một ngôn ngữ lập trình bậc cao, hướng đối tượng, bảo mật và mạnh mẽ, được phát triển bởi Sun Microsystems vào năm 1995. Với phương châm \"Write Once, Run Anywhere\", Java cho phép các chương trình được viết một lần và chạy trên nhiều nền tảng khác nhau nhờ vào máy ảo Java (JVM). Đây là một ngôn ngữ đa nền tảng, được sử dụng rộng rãi trong nhiều lĩnh vực như phát triển ứng dụng web, di động, doanh nghiệp, và hệ thống nhúng.',1,1,13),(10,'String là gì?','Trong lập trình, string là kiểu dữ liệu biểu diễn một chuỗi ký tự, dùng để lưu trữ và xử lý văn bản.',1,1,14),(11,'Exception là gì?','Exception là một thuật ngữ trong lập trình và công nghệ thông tin, dùng để chỉ một tình huống hoặc điều kiện đặc biệt xảy ra trong quá trình thực thi chương trình, khiến chương trình không thể tiếp tục hoạt động bình thường. Khi một exception xảy ra, chương trình sẽ dừng lại và chuyển quyền kiểm soát đến một đoạn mã đặc biệt gọi là \"exception handler\" để xử lý tình huống này.',1,1,15),(12,'Reflection là gì?',NULL,1,1,16),(13,'Java 8 là gì?','Java 8, released on March 18, 2014, is a revolutionary version of the Java programming language and platform. It introduced significant enhancements to the language, JVM, tools, and libraries, making it a milestone in Java\'s evolution.',1,1,17),(14,'Java 17 là gì ?','Java 17 là phiên bản mới nhất của ngôn ngữ lập trình Java, được phát hành vào ngày 15 tháng 9 năm 2021. Đây là phiên bản Long-Term Support (LTS) cho Java SE, cho phép người dùng sử dụng các tệp biên dịch JDK 17 miễn phí trong sản xuất và tái phân phối. Java 17 bao gồm nhiều tính năng mới, trong đó có gần gũi hơn với các tệp số nguyên ngẫu nhiên và các tệp mã điều khiển cho các hàm ngoại giao và API bộ nhớ. Phiên bản này cũng có các tính năng bảo mật như các tệp mã điều khiển có ngữ cảnh cho việc khai thác dữ liệu',1,1,18);
/*!40000 ALTER TABLE `questions` ENABLE KEYS */;
UNLOCK TABLES;

